        task: { type: "string", description: "Alias for goal." },
        message: { type: "string", description: "What the teacher says to the apprentice; can include steps, links, local file paths, JSON events, Markdown/CSV tables, approval, or correction." },
        teacherMessage: { type: "string", description: "Teacher explanation when no artifact is available." },
        teacherStyle: { type: "string", description: "Optional teacher style or learning-method hint, such as steps, examples, voice, overlay sketch, logs, fewer questions, or correction-first." },
        teachingStyle: { type: "string", description: "Alias for teacherStyle." },
        learningMethod: { type: "string", description: "How this teacher prefers to teach or correct the apprentice." },
        teacherMethod: { type: "string", description: "Alias for learningMethod." },
        parametricDrawingLogic: { type: "boolean", description: "When true, create a universal detail logic kit for CAD/drawing/model/output artifacts before generation." },
        universalDetailLogic: { type: "boolean", description: "Alias for parametricDrawingLogic." },
        featureDataLogic: { type: "boolean", description: "Alias for parametricDrawingLogic." },
