function existingJsonPath(value) {
  if (typeof value !== "string" || !value.trim()) return "";
  const direct = value.trim();
  if (existsSync(direct)) return resolve(direct);
  const repoRelative = resolve(repoRoot, direct);
  return existsSync(repoRelative) ? repoRelative : "";
}

function payloadFromTextByFormat(value = "", format) {
  const text = textExampleValue(value);
  if (!text.includes(format)) return null;
  for (const parsed of parseJsonCandidatesFromText(text)) {
    if (parsed && typeof parsed === "object" && parsed.format === format) return parsed;
  }
  return null;
}

function softwareProfileFromInput(input = {}) {
  const direct = input.softwareProfile ?? input.softwareCapabilityProfile ?? input.capabilityProfile;
  if (direct && typeof direct === "object" && direct.format === "transparent_ai_software_capability_profile_v1") return direct;
  const path = existingJsonPath(direct);
  if (path) return path;
  const parsedDirect = payloadFromTextByFormat(direct, "transparent_ai_software_capability_profile_v1");
  if (parsedDirect) return parsedDirect;
  return (
    payloadFromTextByFormat(input.message, "transparent_ai_software_capability_profile_v1") ??
    payloadFromTextByFormat(input.teacherMessage, "transparent_ai_software_capability_profile_v1")
  );
}

function softwareProbeResultFromInput(input = {}) {
  const direct = input.softwareProbeResult ?? input.probeResult ?? input.probe;
  if (direct && typeof direct === "object" && direct.format === "transparent_ai_software_capability_probe_result_v1") return direct;
  const path = existingJsonPath(direct);
  if (path) return path;
  const parsedDirect = payloadFromTextByFormat(direct, "transparent_ai_software_capability_probe_result_v1");
  if (parsedDirect) return parsedDirect;
  return (
    payloadFromTextByFormat(input.message, "transparent_ai_software_capability_probe_result_v1") ??
    payloadFromTextByFormat(input.teacherMessage, "transparent_ai_software_capability_probe_result_v1")
  );
}

function softwareObserverQueueFromInput(input = {}) {
  const direct = input.softwareObserverQueue ?? input.observerQueue ?? input.queue;
  if (direct && typeof direct === "object" && direct.format === "transparent_ai_software_observer_queue_v1") return direct;
  const path = existingJsonPath(direct);
  if (path) return path;
  const parsedDirect = payloadFromTextByFormat(direct, "transparent_ai_software_observer_queue_v1");
  if (parsedDirect) return parsedDirect;
  const messagePath = existingJsonPath(input.message) || existingJsonPath(input.teacherMessage);
  if (messagePath) {
    try {
      const parsed = JSON.parse(readFileSync(messagePath, "utf8"));
      if (parsed?.format === "transparent_ai_software_observer_queue_v1") return messagePath;
    } catch {
      // Keep normal teaching routes available if the pasted path is not an observer queue.
    }
  }
  return (
    payloadFromTextByFormat(input.message, "transparent_ai_software_observer_queue_v1") ??
    payloadFromTextByFormat(input.teacherMessage, "transparent_ai_software_observer_queue_v1")
  );
}

function persistSoftwareObserverQueuePayload(input = {}, payload) {
  if (!payload) return "";
  if (typeof payload === "string") return payload;
  const outputDir = resolve(repoRoot, ".transparent-apprentice", "software-observer-queue-inputs");
  mkdirSync(outputDir, { recursive: true });
  const firstItem = Array.isArray(payload.queue) ? payload.queue[0] : {};
  const safeSoftware =
    String(input.software ?? input.app ?? firstItem?.software ?? "software-queue")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 48) || "software-queue";
  const queuePath = join(outputDir, `${new Date().toISOString().replace(/[:.]/g, "-")}-${safeSoftware}-observer-queue.json`);
  writeFileSync(queuePath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
  return queuePath;
}

