function hasAutomaticLowTokenLearningRunnerIntent(...values) {
  const text = values
    .filter((value) => value !== undefined && value !== null)
    .map((value) => textExampleValue(value).toLowerCase())
    .join(" ");
  if (!text.trim()) return false;
  const automatic = [
    "automatic low-token learning",
    "auto low-token learning",
    "automatic log learning",
    "periodic learning",
    "recurring learning",
    "keep learning from logs",
    "run automatically",
    "\u81ea\u52a8\u4f4e token \u5b66\u4e60",
    "\u81ea\u52a8\u8bfb\u53d6\u65e5\u5fd7",
    "\u81ea\u52a8\u5b66\u4e60",
    "\u5468\u671f\u5b66\u4e60",
    "\u6301\u7eed\u5b66\u4e60"
  ].some((marker) => text.includes(marker));
  const lowTokenLogs = [
    "low-token",
    "low token",
    "log",
    "logs",
    "\u4f4e token",
    "\u65e5\u5fd7"
  ].some((marker) => text.includes(marker));
  return automatic && lowTokenLogs;
}

