function persistAdaptiveObserverPayload(input = {}, payload, suffix) {
  if (!payload) return "";
  if (typeof payload === "string") return payload;
  const outputDir = resolve(repoRoot, ".transparent-apprentice", "adaptive-observer-inputs");
  mkdirSync(outputDir, { recursive: true });
  const safeSoftware =
    String(input.software ?? input.app ?? payload.software ?? "software")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 48) || "software";
  const payloadPath = join(outputDir, `${new Date().toISOString().replace(/[:.]/g, "-")}-${safeSoftware}-${suffix}.json`);
  writeFileSync(payloadPath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
  return payloadPath;
}

function buildAdaptiveObserverArgs(input = {}, profilePayload, probePayload) {
  const profilePath = persistAdaptiveObserverPayload(input, profilePayload, "software-profile");
  if (!profilePath) return null;
  const args = ["--profile", profilePath];
  const probePath = persistAdaptiveObserverPayload(input, probePayload, "software-probe-result");
  if (probePath) args.push("--probe-result", probePath);
  if (input.outputDir) args.push("--output-dir", input.outputDir);
  return args;
}

