function respond(id, result, error) {
  const payload = error
    ? { jsonrpc: "2.0", id, error: { code: -32000, message: String(error.message ?? error) } }
    : { jsonrpc: "2.0", id, result };
  process.stdout.write(`${JSON.stringify(payload)}\n`);
}

const rl = readline.createInterface({ input: process.stdin });
rl.on("line", async (line) => {
  if (!line.trim()) return;
  let message;
  try {
    message = JSON.parse(line);
  } catch (error) {
    respond(null, null, error);
    return;
  }

  try {
    if (message.method === "initialize") {
      respond(message.id, {
        protocolVersion: "2024-11-05",
        capabilities: { tools: {} },
        serverInfo: { name: "ai-apprentice", version: "1.0.0" }
      });
      return;
    }

    if (message.method === "notifications/initialized") {
      return;
    }

    if (message.method === "tools/list") {
      respond(message.id, {
        tools: listedTools(),
        mode: toolSurfaceMode(),
        advancedToolsAvailableWithEnv: "TRANSPARENT_AI_APPRENTICE_TOOL_MODE=advanced",
        fullMaintainerToolsAvailableWithEnv: "TRANSPARENT_AI_APPRENTICE_TOOL_MODE=full"
      });
      return;
    }

    if (message.method === "tools/call") {
      respond(message.id, await callTool(message.params?.name, message.params?.arguments ?? {}));
      return;
    }

    respond(message.id, {});
  } catch (error) {
    respond(message.id, null, error);
  }
});
